import { NewsItemData, IndexData, QuoteData, MarketStatusData, StatsData } from "./types";

const BACKEND_URL = "http://localhost:3001";

export async function fetchNews(limit = 1000, beforeId?: number): Promise<NewsItemData[]> {
  const params = new URLSearchParams({ limit: String(limit) });
  if (beforeId) params.set("before", String(beforeId));
  const res = await fetch(`${BACKEND_URL}/api/news?${params}`);
  return res.json();
}

export async function fetchStats(): Promise<StatsData> {
  const res = await fetch(`${BACKEND_URL}/api/stats`);
  return res.json();
}

export async function fetchIndices(): Promise<IndexData[]> {
  const res = await fetch(`${BACKEND_URL}/api/market/indices`);
  return res.json();
}

export async function fetchQuote(symbol: string): Promise<QuoteData> {
  const res = await fetch(`${BACKEND_URL}/api/market/quote/${encodeURIComponent(symbol)}`);
  return res.json();
}

export interface FullQuoteData {
  symbol: string;
  companyName: string;
  industry: string;
  isin: string;
  ltp: number;
  change: number;
  changePercent: number;
  open: number;
  high: number;
  low: number;
  previousClose: number;
  close: number;
  vwap: number;
  volume: number;
  deliveryQuantity: number;
  deliveryPercent: number;
  weekHigh52: number;
  weekLow52: number;
  upperBand: number;
  lowerBand: number;
  faceValue: number;
  totalBuyQuantity: number;
  totalSellQuantity: number;
  totalTradedVolume: number;
  totalTradedValue: number;
  bid: { price: number; quantity: number }[];
  ask: { price: number; quantity: number }[];
}

export async function fetchFullQuote(symbol: string): Promise<FullQuoteData> {
  const res = await fetch(`${BACKEND_URL}/api/market/quote-full/${encodeURIComponent(symbol)}`);
  return res.json();
}

export async function fetchNewsByTicker(ticker: string, limit = 200): Promise<NewsItemData[]> {
  const all = await fetchNews(limit);
  return all.filter((item) =>
    item.tickers.some((t) => t.toUpperCase() === ticker.toUpperCase())
  );
}

export async function fetchMarketStatus(): Promise<MarketStatusData[]> {
  const res = await fetch(`${BACKEND_URL}/api/market/status`);
  return res.json();
}

export interface StockSearchResult {
  symbol: string;
  name: string;
  type: string;
}

export async function searchStocks(query: string): Promise<StockSearchResult[]> {
  if (query.length < 2) return [];
  const res = await fetch(`${BACKEND_URL}/api/market/search?q=${encodeURIComponent(query)}`);
  return res.json();
}

export function createSSEConnection(
  onMessage: (item: NewsItemData) => void,
  onConnect: () => void,
  onError: () => void
): EventSource {
  const es = new EventSource(`${BACKEND_URL}/api/stream`);

  es.onopen = () => onConnect();

  es.onmessage = (event) => {
    try {
      const data = JSON.parse(event.data);
      if (data.type === "connected") return;
      onMessage(data);
    } catch {
      // ignore
    }
  };

  es.onerror = () => onError();

  return es;
}
